class Player{constructor({media:e}){this.isExternalMedia=!1,e?(this.media=e,this.isExternalMedia=!0):this.media=document.createElement("audio")}on(e,i){return this.media.addEventListener(e,i),()=>this.media.removeEventListener(e,i)}destroy(){this.isExternalMedia||this.media.remove()}loadUrl(e){this.media.src=e}getCurrentTime(){return this.media.currentTime}play(){this.media.play()}pause(){this.media.pause()}isPlaying(){return 0<this.media.currentTime&&!this.media.paused&&!this.media.ended}seekTo(e){this.media.currentTime=e}}export default Player;